// =======================================================
// COMPARAÇÃO:
// A: TRIAGEM ENCONTROU
// B: RETORNA PLANILHA TÉCNICO
// Chave igual nos dois nós:
// 'DATA QUE A COLUNA DATA TRIAGEM FOI PREENCHIDA'
// Retorna apenas o que NÃO deu match
// =======================================================

// Normalizador seguro (evita erro por espaço, caixa, etc.)
const norm = (v) =>
  String(v ?? "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");

// Nome da chave
const KEY = 'DATA QUE A COLUNA PROCURAR MATERIAL FOI PREENCHIDA';

// Itens dos nós
const triagemEncontrou = $items('TRIAGEM ENCONTROU');
const retornaTecnico = $items('RETORNA PLANILHA TÉCNICO');

// Cria um Set com todas as datas do nó B
const datasTecnico = new Set(
  retornaTecnico
    .map(i => norm(i.json?.[KEY]))
    .filter(v => v !== "")
);

// Filtra o nó A: só o que NÃO está no nó B
const resultado = triagemEncontrou.filter(i => {
  const dataA = norm(i.json?.[KEY]);
  return dataA !== "" && !datasTecnico.has(dataA);
});

// Retorno padrão n8n
return resultado.map(i => ({ json: i.json }));

