// =======================================================
// COMPARAÇÃO:
// - Fonte A: PROCURAR MATERIAL
// - Fonte B: RETORNA PLANILHA TRIAGEM
// Retorna o que está em A e NÃO está em B
// Chave de comparação:
// 'DATA QUE A COLUNA PROCURAR MATERIAL FOI PREENCHIDA'
// =======================================================

// Normalizador seguro
const norm = (v) => String(v ?? "").trim();

// 🔹 Itens do nó PROCURAR MATERIAL
const procurarMaterial = $items("PROCURAR MATERIAL");

// 🔹 Itens do nó RETORNA PLANILHA TRIAGEM (entrada padrão)
const triagem = $items("RETORNA PLANILHA TRIAGEM");

// 🔹 Cria um Set com todas as datas da TRIAGEM
const datasTriagem = new Set(
  triagem
    .map(i =>
      norm(i.json['DATA QUE A COLUNA PROCURAR MATERIAL FOI PREENCHIDA'])
    )
    .filter(v => v !== "")
);

// 🔹 Filtra PROCURAR MATERIAL:
// só retorna o que NÃO existe na TRIAGEM
const resultado = procurarMaterial.filter(i => {
  const dataProcurar = norm(
    i.json['DATA QUE A COLUNA PROCURAR MATERIAL FOI PREENCHIDA']
  );

  return dataProcurar && !datasTriagem.has(dataProcurar);
});

// 🔹 Retorno no padrão do n8n
return resultado.map(i => ({ json: i.json }));

// =======================================================
// FILTRO:
// NÃO retorna a linha se OBSERVAÇÕES ÁREA TRIAGEM
// contiver qualquer variação de:
// REPETIR / REPETICAO / REPETIÇÃO
// =======================================================

const itens = $input.all();

// Normalizador robusto
const norm = (v) =>
  String(v ?? "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, ""); // remove acentos

// Regex para REPETIR / REPETICAO / REPETIÇÃO
const regexRepeticao = /\brepetir\b|\brepeticao\b/;

const resultado = itens.filter(item => {
  const obs = norm(item.json?.['OBSERVAÇÕES ÁREA TRIAGEM']);
  return !regexRepeticao.test(obs);
});

// Retorno padrão n8n
return resultado.map(i => ({ json: i.json }));

return items.map(item => {
  item.json.destinatario = String(item.json.destinatario || "120363406086322772@g.us");
  item.json.mensagem = String(item.json.mensagem || "Teste");
  return item;
});

